int findLongestStringChain(vector<string>& wordList) {
        sort(wordList.begin(), wordList.end(), [](const string& a, const string& b) {
            return a.size() < b.size();
        });
        unordered_map<string, int> dp;
        int resultNumber = 1;
        for (const string& wordString : wordList) {
            int best = 1;
            for (int i = 0; i < (int)wordString.size(); ++i) {
                string prev = wordString.substr(0, i) + wordString.substr(i + 1);
                if (dp.count(prev)) {
                    best = max(best, dp[prev] + 1);
                }
            }
            dp[wordString] = best;
            resultNumber = max(resultNumber, best);
        }
        return resultNumber;
    }

