def findLongestStringChain(word_list):
    if not word_list:
        return 0

    # Sort words by length
    word_list.sort(key=len)

    dp = {}
    max_chain = 1

    for word in word_list:
        best = 1
        for i in range(len(word)):
            prev = word[:i] + word[i+1:]
            best = max(best, dp.get(prev, 0) + 1)
        dp[word] = best
        max_chain = max(max_chain, best)

    return max_chain

