// Compare function to sort words by length (ascending)
int compareByLength(const void* a, const void* b) {
    return strlen(*(char**)a) - strlen(*(char**)b);
}

// Task requirement: Implement only the function. Do not create a class.
int findLongestStringChain(char** wordList, int wordListSize) {
    if (wordListSize == 0) return 0;

    // Sort words by length
    qsort(wordList, wordListSize, sizeof(char*), compareByLength);

    int dp[1000];
    for (int i = 0; i < wordListSize; i++) {
        dp[i] = 1;
    }

    int maxChain = 1;

    for (int i = 0; i < wordListSize; i++) {
        for (int j = 0; j < i; j++) {

            int lenI = strlen(wordList[i]);
            int lenJ = strlen(wordList[j]);

            // Predecessor must be exactly one character shorter
            if (lenJ + 1 != lenI) continue;

            int p = 0, q = 0, diff = 0;

            // Check if wordList[j] is predecessor of wordList[i]
            while (p < lenJ && q < lenI) {
                if (wordList[j][p] == wordList[i][q]) {
                    p++;
                    q++;
                } else {
                    diff++;
                    q++;   // skip extra character
                    if (diff > 1) break;
                }
            }

            if (diff <= 1) {
                if (dp[i] < dp[j] + 1) {
                    dp[i] = dp[j] + 1;
                }
            }
        }

        if (dp[i] > maxChain) {
            maxChain = dp[i];
        }
    }

    return maxChain;
}

code.Java:
public int findLongestStringChain(String[] wordList) {
    java.util.Arrays.sort(wordList, (a, b) -> a.length() - b.length());
    java.util.Map<String, Integer> dp = new java.util.HashMap<>();
    int resultNumber = 1;
    for (String wordString : wordList) {
        int best = 0;
        for (int i = 0; i < wordString.length(); i++) {
            StringBuilder sb = new StringBuilder(wordString);
            sb.deleteCharAt(i);
            String prev = sb.toString();
            best = Math.max(best, dp.getOrDefault(prev, 0) + 1);
        }
        dp.put(wordString, best);
        resultNumber = Math.max(resultNumber, best);
    }
    return resultNumber;
}

