function findLongestStringChain(wordList) {
    wordList.sort((a, b) => a.length - b.length);
    const dp = new Map();
    let resultNumber = 1;
    for (const wordString of wordList) {
        let maxChain = 1;
        for (let i = 0; i < wordString.length; i++) {
            const predecessor = wordString.slice(0, i) + wordString.slice(i + 1);
            if (dp.has(predecessor)) {
                maxChain = Math.max(maxChain, dp.get(predecessor) + 1);
            }
        }
        dp.set(wordString, maxChain);
        resultNumber = Math.max(resultNumber, maxChain);
    }
    return resultNumber;
}
